import{_ as n,o as h,c,a0 as o}from"./chunks/framework.jwovEGr5.js";const e=JSON.parse('{"title":"Thiết lập Công ty","description":"","frontmatter":{"title":"Thiết lập Công ty"},"headers":[],"relativePath":"company-setup.md","filePath":"company-setup.md"}'),i={name:"company-setup.md"};function g(a,t,r,d,l,u){return h(),c("div",null,[...t[0]||(t[0]=[o('<h1 id="thiet-lap-cong-ty" tabindex="-1">Thiết lập Công ty <a class="header-anchor" href="#thiet-lap-cong-ty" aria-label="Permalink to &quot;Thiết lập Công ty&quot;">​</a></h1><h2 id="cong-ty-la-gi" tabindex="-1">Công ty là gì? <a class="header-anchor" href="#cong-ty-la-gi" aria-label="Permalink to &quot;Công ty là gì?&quot;">​</a></h2><p><strong>Công ty</strong> là thực thể pháp lý trung tâm trong hệ thống ABNERP. Mọi giao dịch — từ hóa đơn, đơn hàng, chứng từ kế toán đến báo cáo tài chính — đều được gắn với một công ty cụ thể.</p><p>Khi bạn tạo tài khoản ABNERP lần đầu tiên, hệ thống sẽ hướng dẫn bạn tạo <strong>công ty đầu tiên</strong>. Đây là bước bắt buộc trước khi bạn có thể sử dụng bất kỳ tính năng nào khác của hệ thống.</p><h2 id="tao-cong-ty-moi" tabindex="-1">Tạo công ty mới <a class="header-anchor" href="#tao-cong-ty-moi" aria-label="Permalink to &quot;Tạo công ty mới&quot;">​</a></h2><h3 id="cac-buoc-thuc-hien" tabindex="-1">Các bước thực hiện <a class="header-anchor" href="#cac-buoc-thuc-hien" aria-label="Permalink to &quot;Các bước thực hiện&quot;">​</a></h3><ol><li>Đăng nhập vào tài khoản ABNERP của bạn</li><li>Truy cập vào <strong>Trang chủ &gt; Công ty &gt; Công ty</strong></li><li>Nhấn nút <strong>+ Thêm Công ty</strong> (hoặc <strong>+ Add Company</strong>)</li><li>Điền các thông tin bắt buộc</li><li>Nhấn <strong>Lưu</strong></li></ol><h3 id="thong-tin-cong-ty" tabindex="-1">Thông tin công ty <a class="header-anchor" href="#thong-tin-cong-ty" aria-label="Permalink to &quot;Thông tin công ty&quot;">​</a></h3><p>Bảng dưới đây mô tả các trường thông tin quan trọng khi tạo công ty:</p><table tabindex="0"><thead><tr><th>Trường</th><th>Bắt buộc</th><th>Mô tả</th></tr></thead><tbody><tr><td><strong>Tên công ty</strong></td><td>Có</td><td>Tên đầy đủ của công ty (ví dụ: Công ty TNHH ABC)</td></tr><tr><td><strong>Tên viết tắt</strong></td><td>Có</td><td>Tên viết tắt dùng trong báo cáo và chứng từ (ví dụ: ABC)</td></tr><tr><td><strong>Quốc gia</strong></td><td>Có</td><td>Quốc gia đăng ký kinh doanh của công ty. Quyết định sơ đồ tài khoản, thuế, và định dạng mặc định</td></tr><tr><td><strong>Tiền tệ</strong></td><td>Có</td><td>Tiền tệ mặc định cho các giao dịch kế toán</td></tr><tr><td><strong>Mã số thuế</strong></td><td>Không</td><td>Mã số thuế / mã số doanh nghiệp</td></tr><tr><td><strong>Địa chỉ</strong></td><td>Không</td><td>Địa chỉ trụ sở chính của công ty</td></tr><tr><td><strong>Năm tài chính</strong></td><td>Có</td><td>Kỳ kế toán năm. Có thể chọn năm dương lịch hoặc năm tài chính theo quy định</td></tr><tr><td><strong>Ngày bắt đầu năm tài chính</strong></td><td>Có</td><td>Ngày bắt đầu của năm tài chính (ví dụ: 01/01 đối với năm dương lịch)</td></tr><tr><td><strong>Logo</strong></td><td>Không</td><td>Logo của công ty, hiển thị trên hóa đơn và báo cáo</td></tr><tr><td><strong>Website</strong></td><td>Không</td><td>Địa chỉ trang web của công ty</td></tr><tr><td><strong>Email</strong></td><td>Không</td><td>Email liên hệ mặc định của công ty</td></tr><tr><td><strong>Điện thoại</strong></td><td>Không</td><td>Số điện thoại liên hệ</td></tr></tbody></table><h3 id="cau-hinh-bo-sung" tabindex="-1">Cấu hình bổ sung <a class="header-anchor" href="#cau-hinh-bo-sung" aria-label="Permalink to &quot;Cấu hình bổ sung&quot;">​</a></h3><p>Sau khi tạo công ty, bạn có thể cấu hình thêm:</p><ul><li><strong>Sơ đồ tài khoản</strong>: ABNERP tự động tạo sơ đồ tài khoản phù hợp với quốc gia đã chọn</li><li><strong>Mẫu hóa đơn</strong>: Tùy chỉnh giao diện hóa đơn, chứng từ</li><li><strong>Thuế</strong>: Thiết lập các loại thuế áp dụng (VAT, thuế TNCN, v.v.)</li><li><strong>Phân quyền</strong>: Cấu hình quyền truy cập cho người dùng trong công ty</li></ul><h2 id="quan-ly-nhieu-cong-ty" tabindex="-1">Quản lý nhiều công ty <a class="header-anchor" href="#quan-ly-nhieu-cong-ty" aria-label="Permalink to &quot;Quản lý nhiều công ty&quot;">​</a></h2><p>ABNERP hỗ trợ quản lý <strong>nhiều công ty</strong> trên cùng một hệ thống. Điều này rất hữu ích khi:</p><ul><li>Bạn sở hữu nhiều doanh nghiệp khác nhau</li><li>Bạn cần tách riêng kế toán cho các chi nhánh</li><li>Bạn quản lý công ty mẹ và công ty con</li></ul><p>Mỗi công ty có bộ dữ liệu riêng biệt nhưng vẫn có thể chia sẻ các danh mục chung như khách hàng, nhà cung cấp, mặt hàng.</p><h2 id="luu-y" tabindex="-1">Lưu ý <a class="header-anchor" href="#luu-y" aria-label="Permalink to &quot;Lưu ý&quot;">​</a></h2><ul><li>Tên viết tắt nên ngắn gọn, không có dấu tiếng Việt để tránh lỗi hiển thị trong báo cáo</li><li>Quốc gia của công ty không thể thay đổi sau khi lưu, hãy kiểm tra kỹ trước khi xác nhận</li><li>Bạn có thể thay đổi các thông tin khác bất kỳ lúc nào sau khi tạo công ty</li></ul>',19)])])}const y=n(i,[["render",g]]);export{e as __pageData,y as default};
